if (Location.exitRegionLocation.DeviceName !== 'Home') {
  Ecobee.turnOff.skip();
} else {
  const lat1 = parseFloat(Location.exitRegionLocation.Latitude);
  const lon1 = parseFloat(Location.exitRegionLocation.Longitude);
  const lat2 = parseFloat(Meta.currentUser.homeLatitude);
  const lon2 = parseFloat(Meta.currentUser.homeLongitude);
  const R = 6371; // Earth's radius in kilometers
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
            Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
            Math.sin(dLon / 2) * Math.sin(dLon / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  const distance = R * c;
  if (distance <= 100) {
    Ecobee.turnOff.skip();
  }
}
