  Arlo.disarm.skip();
  Email.sendMeEmail.skip();
} else {
  Arlo.disarm.setDisarmCode('mydisarmcode');
  const subject = `August lock unlocked at ${location}`;
  const body = `User ${username} unlocked the August lock at ${location} on ${time}.`;
  Email.sendMeEmail.setSubject(subject);
  Email.sendMeEmail.setBody(body);
}

