If no sunrise is detected, the action should be skipped.
The action should send a notification with the current temperature in Celsius and a picture of the current weather condition.
The picture URL should be set to the appropriate image URL based on the current condition.

const sunrise = Weather.sunRises.SunriseAt;
const current = Meta.currentUserTime.format('YYYY-MM-DD HH:mm');
const tempC = Weather.sunRises.CurrentTempFahrenheit;
const condition = Weather.sunRises.CurrentCondition.toLowerCase();

// Check if sunrise occurred within the last 15 minutes
const sunriseMoment = Meta.currentUserTime.clone().set({
  year: new Date(sunrise).getFullYear(),
  month: new Date(sunrise).getMonth(),
  date: new Date(sunrise).getDate(),
  hour: new Date(sunrise).getHours(),
  minute: new Date(sunrise).getMinutes(),
  second: new Date(sunrise).getSeconds()
});
const diffMinutes = Meta.currentUserTime.diff(sunriseMoment, 'minutes');
if (diffMinutes > 15 || diffMinutes < 0) {
  IfNotifications.sendNotification.skip();
} else {
  // Set notification message with temperature and condition
  const tempCStr = (tempC * 5 / 9).toFixed(0);
  const message = `Good morning! Current temperature is ${tempCStr}°C. The weather is currently ${condition}.`;
  IfNotifications.sendNotification.setMessage(message);
  // Set picture URL based on condition
  const picUrl = Weather.sunRises.ConditionImageURL;
  IfNotifications.sendNotification.setHighPriorityImage(picUrl);
}

