If no office location is defined, the action should be skipped.
If the office location is defined but the user is not leaving the office, the action should be skipped.
If the user is leaving the office, the action should send a message with the text 'Get tea!' and include a web page preview if available.

// Define the office location coordinates (latitude, longitude)
const OFFICE_LATITUDE = 40.7128;
const OFFICE_LONGITUDE = -74.0060;

// Define a small tolerance for location comparison
const TOLERANCE = 0.0005;

// Check if user is leaving the office
const isLeavingOffice = () => {
  const lat = parseFloat(Location.exitRegionLocation.Latitude);
  const lon = parseFloat(Location.exitRegionLocation.Longitude);
  return Math.abs(lat - OFFICE_LATITUDE) <= TOLERANCE && Math.abs(lon - OFFICE_LONGITUDE) <= TOLERANCE;
};

// Check if user is entering the office
const isEnteringOffice = () => {
  const lat = parseFloat(Location.enterRegionLocation.Latitude);
  const lon = parseFloat(Location.enterRegionLocation.Longitude);
  return Math.abs(lat - OFFICE_LATITUDE) <= TOLERANCE && Math.abs(lon - OFFICE_LONGITUDE) <= TOLERANCE;
};

// If not leaving office, skip action
if (!isLeavingOffice()) {
  Telegram.sendMessage.skip();
} else {
  // Set message text and include web page preview if available
  Telegram.sendMessage.setText('Get tea!');
  Telegram.sendMessage.setIncludeWebPagePreview('true');
}

// If entering office, skip action
if (isEnteringOffice()) {
  Telegram.sendMessage.skip();
}

