// Check if the event starts within 10 minutes from now
const now = Meta.currentUserTime.clone();
const eventTime = Meta.currentUserTime.clone();
if (eventStarts) {
  eventTime = moment(eventStarts);
}
const diffMinutes = eventTime.diff(now, 'minutes');
const isWithin10Minutes = diffMinutes >= 0 && diffMinutes <= 10;

