  // Set the A/C to turn on 10 minutes before the event starts
  const eventStartMoment = moment(eventStarts);
  const turnOnTime = eventStartMoment.clone().subtract(10, 'minutes');
  const turnOnStr = turnOnTime.format('YYYY-MM-DD HH:mm');
  Airco.turnOn.setTurnOnTime(turnOnStr);
}

