const homeLatitude = 40.7128;
const homeLongitude = -74.0060;
const tolerance = 0.0005;

// Check if user is at home
function isAtHome(latStr, lonStr) {
  const lat = parseFloat(latStr);
  const lon = parseFloat(lonStr);
  if (isNaN(lat) || isNaN(lon)) return false;
  return Math.abs(lat - homeLatitude) <= tolerance && Math.abs(lon - homeLongitude) <= tolerance;
}

