package.ifttt.sendIftttNotification.setTitle('Barometric Pressure Alert');
const pressure = parseFloat(Weather.currentPressureFallsBelow.Pressure);
const homeLat = parseFloat(Weather.currentPressureFallsBelow.LocationLatitude);
const homeLon = parseFloat(Weather.currentPressureFallsBelow.LocationLongitude);
const userLat = parseFloat(Weather.currentPressureFallsBelow.UserLatitude);
const userLon = parseFloat(Weather.currentPressureFallsBelow.UserLongitude);
// Check if the current pressure is below 1000 mB and the location is close to the user location
// Here we assume the user location is (userLat, userLon) and the home location is (homeLat, homeLon)
// We use a threshold distance of 1 km (1000 m)
const distLat = Math.abs(userLat - homeLat);
const distLon = Math.abs(userLon - homeLon);
const distKm = Math.sqrt(distLat * distLat + distLon * distLon) * 1000 / 1000; // convert m to km
if (pressure < 1000 || distKm > 1) {
  package.ifttt.sendIftttNotification.skip();
} else {
  package.ifttt.sendIftttNotification.setMessage(`Barometric pressure dropped below 1000 mB at your home weather station. Current pressure: ${pressure} mB.`);
}

